noncompliant:
try
{
    DoSomething();
}
finally
{
    throw new InvalidOperationException(); // Noncompliant: masks exceptions from try block
}

try
{
    throw new ArgumentException();
}
finally
{
    CleanupResources();
    throw new Exception("Cleanup failed"); // Noncompliant: will mask ArgumentException
}

compliant:
try
{
    DoSomething();
}
finally
{
    // Cleanup without throwing
    CleanupResources();
}

try
{
    DoSomething();
}
finally
{
    try
    {
        CleanupResources();
    }
    catch (Exception ex)
    {
        // Log the exception but don't throw
        logger.LogError(ex, "Cleanup failed");
    }
}
